.btn-primary:hover {
  box-shadow: var(--shadow-solid-hover);
  transform: translate(3px, 3px);
  background-color: var(--clr-mint);
}

.btn-primary:active {
  transform: translate(4px, 4px);
  box-shadow: none;
}

.btn-outline {
  background-color: var(--clr-white);
  color: var(--clr-black);
  box-shadow: var(--shadow-solid);
}

.btn-outline:hover {
  box-shadow: var(--shadow-solid-hover);
  transform: translate(3px, 3px);
  background-color: var(--clr-yellow);
}

.btn-outline:active {
  transform: translate(4px, 4px);
  box-shadow: none;
}

.btn-lg {
  font-size: var(--fs-md);
  padding: 0.9rem 2.25rem;
}

/* ==========================================================================
   Navbar
   ========================================================================== */
.navbar {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  background-color: rgba(250, 250, 250, 0.92);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-bottom: var(--border-width) solid var(--clr-black);
  z-index: 1000;
  transition: var(--transition);
}

.navbar.scrolled {
  padding: 0;
}

.nav-container {
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 80px;
  padding: 0 var(--space-lg);
}

.logo {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.logo-img {
  height: 52px;
  width: auto;
}

.logo-text {
  font-size: var(--fs-xl);
  font-weight: 800;
  letter-spacing: var(--ls-wider);
}

.nav-links {
  display: flex;
  align-items: center;
  gap: 2.5rem;
}

.nav-link {
  font-weight: 600;
  font-size: var(--fs-sm);
  text-transform: uppercase;
  letter-spacing: var(--ls-wide);
  position: relative;
  padding: 0.5rem 0;
  color: var(--clr-text);
  outline-offset: 2px;
}

.nav-link:focus-visible {
  outline: var(--focus-outline);
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 0%;
  height: 2.5px;
  background-color: var(--clr-yellow);
  transition: var(--transition);
}

.nav-link:hover::after {
  width: 100%;
}

.nav-btn {
  background-color: var(--clr-yellow);
  padding: 0.55rem 1.5rem;
  border: var(--border-width) solid var(--clr-black);
  font-weight: 700;
  box-shadow: var(--shadow-md);
  transition: var(--transition);
  text-transform: uppercase;
  font-size: var(--fs-sm);
  letter-spacing: var(--ls-wide);
  cursor: pointer;
  outline-offset: 2px;
}

.nav-btn:focus-visible {
  outline: var(--focus-outline);
}

.nav-btn:hover {
  box-shadow: var(--shadow-sm);
  transform: translate(1px, 1px);
  background-color: var(--clr-mint);
}

.nav-btn:active {
  transform: translate(2px, 2px);
  box-shadow: none;
}

.mobile-menu-btn {
  display: none;
  background: none;
  border: none;
  flex-direction: column;
  gap: 6px;
  cursor: pointer;
  padding: 8px;
