}

.mobile-menu-btn:focus-visible {
  outline: var(--focus-outline);
}

.mobile-menu-btn span {
  display: block;
  width: 28px;
  height: 2.5px;
  background-color: var(--clr-black);
  transition: var(--transition);
  pointer-events: none;
}

/* ==========================================================================
   Hero Section
   ========================================================================== */
.hero {
  min-height: 100vh;
  display: flex;
  align-items: center;
  padding-top: 80px;
  position: relative;
  overflow: hidden;
}

.hero-container {
  display: flex;
  justify-content: center;
  position: relative;
  z-index: 1;
}

.hero-content {
  max-width: 680px;
}

.hero-title {
  font-size: var(--fs-7xl);
  font-weight: 900;
  line-height: var(--lh-tight);
  margin-bottom: var(--space-lg);
  letter-spacing: var(--ls-tight);
  color: var(--clr-black);
}

.hero-subtitle {
  font-size: var(--fs-md);
  font-weight: 400;
  max-width: 520px;
  margin-bottom: var(--space-xl);
  color: var(--clr-text-muted);
  line-height: var(--lh-relaxed);
}

.hero-actions {
  display: flex;
  gap: var(--space-md);
}

/* ==========================================================================
   Section Headers
   ========================================================================== */
.section-header {
  text-align: center;
  margin-bottom: var(--space-3xl);
}

.section-title {
  font-size: var(--fs-5xl);
  font-weight: 900;
  margin-bottom: var(--space-lg);
  display: inline-block;
  position: relative;
