   Contact Section
   ========================================================================== */
.bg-dark {
  background-color: var(--clr-black);
  color: var(--clr-white);
}

.title-light {
  color: var(--clr-white);
}

.title-light::after {
  background-color: var(--clr-mint);
  opacity: 0.35;
}

