/* ==========================================================================
   Base Design System - Protocodus
   ========================================================================== */
:root {
  /* Colors based on Logo */
  --clr-bg: #FAFAFA;
  --clr-text: #1A1A1A;
  --clr-yellow: #FFC400;
  --clr-mint: #00FFC3;
  --clr-black: #1A1A1A;
  --clr-white: #FFFFFF;
  --clr-grey: #888888;
  --clr-text-muted: #555555;

  /* Typography */
  --font-primary: 'Space Grotesk', sans-serif;

  /* Typography Scale (1.2x ratio) */
  --fs-xs: 0.75rem;
  --fs-sm: 0.85rem;
  --fs-base: 1rem;
  --fs-md: 1.2rem;
  --fs-lg: 1.45rem;
  --fs-xl: 1.75rem;
  --fs-2xl: 2.1rem;
  --fs-3xl: 2.5rem;
  --fs-4xl: 3rem;
  --fs-5xl: 3.6rem;
  --fs-6xl: 4.3rem;
  --fs-7xl: 5.2rem;

  /* Line Heights */
  --lh-tight: 1.2;
  --lh-snug: 1.5;
  --lh-normal: 1.7;
  --lh-relaxed: 1.8;

  /* Letter Spacing */
  --ls-tight: -0.02em;
  --ls-normal: 0;
  --ls-wide: 1px;
  --ls-wider: 2px;

  /* Layout & Spacing (8px base) */
  --container-width: 1120px;
  --space-xs: 0.5rem;
  --space-sm: 1rem;
  --space-md: 1.5rem;
  --space-lg: 2rem;
  --space-xl: 3rem;
  --space-2xl: 4rem;
  --space-3xl: 5rem;
  --space-4xl: 7rem;

  /* Aesthetics */
  --border-radius: 0px;
  --border-radius-pill: 999px;
  --border-width: 2.5px;
  --shadow-sm: 1px 1px 0px var(--clr-black);
  --shadow-md: 2px 2px 0px var(--clr-black);
  --shadow-lg: 4px 4px 0px var(--clr-black);
  --shadow-xl: 6px 6px 0px var(--clr-black);
  --shadow-solid: 4px 4px 0px var(--clr-black);
  --shadow-solid-hover: 1px 1px 0px var(--clr-black);
  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);

  /* Focus State */
  --focus-outline: 2px solid var(--clr-yellow);
  --focus-outline-mint: 2px solid var(--clr-mint);
}

/* Base Reset */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-primary);
  color: var(--clr-text);
  line-height: var(--lh-normal);
  overflow-x: hidden;
  font-size: var(--fs-base);
}

/* Animated Background (p5.js) */
.bg-animation-container {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;

